use crate::{msg::Ucs03ExecuteMsg, types::ChannelId};
use cosmwasm_std::{Timestamp, Uint64};

#[test]
fn ucs03_send_test() {
    use hex_literal::hex;
    let json_str = r#"{"send":{"channel_id":9,"timeout_height":"0","timeout_timestamp":"1744248392563000000","salt":"0xfd0ff5488c14b15c03d8958b25261c22a42b049894aeb1f33926a1f7ccadaf98","instruction":""}}"#;

    let msg = serde_json_wasm::from_str::<Ucs03ExecuteMsg>(json_str).unwrap();

    assert_eq!(
            msg,
            Ucs03ExecuteMsg::Send {
                channel_id: ChannelId::from_raw(9).unwrap(),
                timeout_height: Uint64::new(0),
                timeout_timestamp: Timestamp::from_nanos(1744248392563000000),
                salt: hex!("fd0ff5488c14b15c03d8958b25261c22a42b049894aeb1f33926a1f7ccadaf98").into(),
                instruction: "".parse().unwrap()
            }
        );
}
